import {
  jestCustomRender as render,
  screen,
  fireEvent,
} from '@mentimeter/jest/dom';
import { trackUser } from '@api/tracking/client';
import { EnableComments } from './EnableComments';

// Mock external dependencies
jest.mock('@api/tracking/client', () => ({
  trackUser: jest.fn(),
}));

jest.mock('@mentimeter/presentation-state', () => ({
  getLatestPresentationId: jest.fn(() => 'test-presentation-id'),
}));

describe('EnableComments Component', () => {
  const handleLiveChatSettingsChangeMock = jest.fn();

  afterEach(() => {
    jest.clearAllMocks(); // Reset mocks after each test
  });

  it('renders the Toggle component with the correct state', () => {
    render(
      <EnableComments
        enabled={true}
        onLiveChatSettingsChange={handleLiveChatSettingsChangeMock}
      />,
    );

    const toggle = screen.getByRole('checkbox', { name: /Enable comments/i });
    expect(toggle).toBeInTheDocument();
    expect(toggle).toBeChecked(); // Because enabled is true
  });

  it('toggles the comments setting and tracks the user event when clicked', () => {
    render(
      <EnableComments
        enabled={false}
        onLiveChatSettingsChange={handleLiveChatSettingsChangeMock}
      />,
    );

    const toggle = screen.getByRole('checkbox', { name: /Enable comments/i });
    expect(toggle).not.toBeChecked(); // Initially false

    // Simulate user clicking the toggle
    fireEvent.click(toggle);

    // Ensure trackUser is called with the right arguments
    expect(trackUser).toHaveBeenCalledWith({
      event: 'Toggled CFA',
      properties: {
        context: 'Mentimote',
        placement: 'Menu',
        enabled: true, // After click, it should become true
        'Presentation id': 'test-presentation-id',
      },
    });

    // Ensure onLiveChatSettingsChange is called with the correct argument
    expect(handleLiveChatSettingsChangeMock).toHaveBeenCalledWith(true);
  });

  it('disables comments on toggle and calls the appropriate functions', () => {
    render(
      <EnableComments
        enabled={true}
        onLiveChatSettingsChange={handleLiveChatSettingsChangeMock}
      />,
    );

    const toggle = screen.getByRole('checkbox', { name: /Enable comments/i });
    expect(toggle).toBeChecked(); // Initially true

    // Simulate user clicking the toggle to disable comments
    fireEvent.click(toggle);

    // Ensure trackUser is called with the correct arguments
    expect(trackUser).toHaveBeenCalledWith({
      event: 'Toggled CFA',
      properties: {
        context: 'Mentimote',
        placement: 'Menu',
        enabled: false, // After click, it should become false
        'Presentation id': 'test-presentation-id',
      },
    });

    // Ensure onLiveChatSettingsChange is called with the correct argument
    expect(handleLiveChatSettingsChangeMock).toHaveBeenCalledWith(false);
  });
});
