import { useCallback } from 'react';
import { Box, Toggle } from '@mentimeter/ragnar-ui';
import { getLatestPresentationId } from '@mentimeter/presentation-state';
import { trackUser } from '@api/tracking/client';

interface PropsT {
  enabled: boolean;
  onLiveChatSettingsChange: (active: boolean) => void;
}

export const EnableComments = ({
  enabled,
  onLiveChatSettingsChange,
}: PropsT) => {
  const toggle = useCallback(() => {
    trackUser({
      event: 'Toggled CFA',
      properties: {
        context: 'Mentimote',
        placement: 'Menu',
        enabled: !enabled,
        'Presentation id': getLatestPresentationId(),
      },
    });
    onLiveChatSettingsChange(!enabled);
  }, [enabled, onLiveChatSettingsChange]);

  return (
    <Box width="100%" mt={2} mb={1}>
      <Toggle
        width="100%"
        id="enable-comments"
        label="Enable comments"
        name="Enable comments"
        checked={enabled}
        position="right"
        onChange={toggle}
      />
    </Box>
  );
};
